int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src, *dst, *temp;
    int min;

    dst = result;
    src = new int[cols];

    // CUDA device memory
    int *d_src, *d_dst, *d_wall_row;
    cudaMalloc(&d_src, cols * sizeof(int));
    cudaMalloc(&d_dst, cols * sizeof(int));
    cudaMalloc(&d_wall_row, cols * sizeof(int));

    pin_stats_reset();

    int threads_per_block = 256;
    int num_blocks = (cols + threads_per_block - 1) / threads_per_block;

    for (int t = 0; t < rows-1; t++) {
        temp = src;
        src = dst;
        dst = temp;

        // Copy src to device
        cudaMemcpy(d_src, src, cols * sizeof(int), cudaMemcpyHostToDevice);
        // Copy wall row to device
        cudaMemcpy(d_wall_row, wall[t+1], cols * sizeof(int), cudaMemcpyHostToDevice);

        // Launch kernel
        pathfinder_kernel<<<num_blocks, threads_per_block>>>(d_src, d_dst, d_wall_row, cols);

        // Copy result back to host
        cudaMemcpy(dst, d_dst, cols * sizeof(int), cudaMemcpyDeviceToHost);
    }

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

#ifdef BENCH_PRINT

    for (int i = 0; cols > i; i++)

            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; cols > i; i++)

            printf("%d ",dst[i]) ;

    printf("\n") ;

#endif

    delete [] data;
    delete [] wall;
    delete [] dst;
    delete [] src;

    cudaFree(d_src);
    cudaFree(d_dst);
    cudaFree(d_wall_row);
}
